INSERT INTO `t_article` (`id`, `user_id`, `category_id`, `article_cover`, `article_title`, `article_content`, `article_type`, `original_url`, `is_top`, `is_delete`, `status`, `like_count`, `view_count`, `created_at`, `updated_at`) VALUES (3, 'root', 2, 'https://static.veweiyi.cn/blog/cover/zhuque.jpg', '从零开始部署博客系统', '# 博客系统部署指南\n\n## 文档说明\n\n本文档是博客系统部署的总体指南，详细介绍了从零开始部署一个完整博客系统的全过程。适合有一定基础的开发者参考。\n\n## 部署流程概览\n\n1. 前期准备\n    - [服务器选型与购买](资源准备（1）服务器准备)\n    - [域名注册与备案](资源准备（2）域名准备)\n    - [SSL证书配置](资源准备（3）SSL证书配置)\n    - [存储服务配置](资源准备（4）存储服务配置)\n\n2. 环境搭建\n    - [Docker环境配置](环境搭建（1）Docker.md)\n    - [MySQL数据库配置](环境搭建（2）MySQL.md)\n    - [Redis缓存配置](环境搭建（3）Redis.md)\n    - [RabbitMQ消息队列配置](环境搭建（4）RabbitMQ.md)\n\n3. 本地开发\n    - [开发环境配置](开发环境（1）基础配置.md)\n    - [配置文件说明](开发环境（2）配置文件.md)\n    - [开发调试指南](开发环境（3）调试指南.md)\n\n4. 生产部署\n    - [服务部署流程](生产部署（1）服务部署.md)\n    - [Nginx配置指南](生产部署（2）Nginx配置.md)\n    - [HTTPS配置说明](生产部署（3）HTTPS配置.md)\n\nTODO\n\n5. 运维管理\n    - [监控系统配置](运维管理（1）监控系统.md)\n    - [日志管理方案](运维管理（2）日志管理.md)\n    - [备份策略说明](运维管理（3）备份策略.md)\n    - [安全加固指南](运维管理（4）安全加固.md)\n\n6. 故障排查\n    - [常见问题处理](故障排查（1）常见问题.md)\n    - [性能优化指南](故障排查（2）性能优化.md)\n\n7. 更新维护\n    - [版本更新流程](更新维护（1）版本更新.md)\n    - [定期维护计划](更新维护（2）维护计划.md)\n', 1, '', 1, 0, 1, 0, 158, '2025-05-05 00:20:03', '2026-05-27 13:51:00');
INSERT INTO `t_article` (`id`, `user_id`, `category_id`, `article_cover`, `article_title`, `article_content`, `article_type`, `original_url`, `is_top`, `is_delete`, `status`, `like_count`, `view_count`, `created_at`, `updated_at`) VALUES (4, 'root', 2, 'https://static.veweiyi.cn/blog/article/qinglong-20241115174624.jpg', '博客网站功能展示', '# 博客网站功能展示\n\n## 前台页面展示\n\n### 移动端适配\n\n|                                                                                                                    |                                                                                                                    |\n|--------------------------------------------------------------------------------------------------------------------|--------------------------------------------------------------------------------------------------------------------|\n| <img src=\"https://veport.oss-cn-beijing.aliyuncs.com/articles/3d6d442430f9de01c2e7cbcb914c1a2a.jpg\" width=\"300\" /> | <img src=\"https://veport.oss-cn-beijing.aliyuncs.com/articles/12431b4262b7e9c2fe1c10d2a9797ad1.jpg\" width=\"300\" /> |\n| <img src=\"https://veport.oss-cn-beijing.aliyuncs.com/articles/d4febe8505c3e3d9f71493972b0cd6ed.jpg\" width=\"300\" /> | <img src=\"https://veport.oss-cn-beijing.aliyuncs.com/articles/c41b4df3ead2d3dd6684a363e8ea4106.png\" width=\"300\" /> |\n\n### PC端适配\n\n|                                                                                                        |\n|--------------------------------------------------------------------------------------------------------|\n| ![blog1.png](https://veport.oss-cn-beijing.aliyuncs.com/articles/b0321e4e4833f12250a2d0bbaf40889b.png) |\n| ![blog2.png](https://veport.oss-cn-beijing.aliyuncs.com/articles/96fb1393414a402d7e7d5e46f1fb6204.png) |\n| ![blog4.png](https://veport.oss-cn-beijing.aliyuncs.com/articles/9e7675104afe9bf523aa7862803bde4f.png) |\n| ![blog5.png](https://veport.oss-cn-beijing.aliyuncs.com/articles/28d8cefb6fc706ad673ef8656a631ecb.png) |\n\n## 后台管理系统展示\n\n|                                                                                                         |\n|---------------------------------------------------------------------------------------------------------|\n| ![admin1.png](https://veport.oss-cn-beijing.aliyuncs.com/articles/37119259612910a845c10517c4c82900.png) |\n| ![admin2.png](https://veport.oss-cn-beijing.aliyuncs.com/articles/106c49bef28297ffe184257e6bae8c5e.png) |\n| ![admin3.png](https://veport.oss-cn-beijing.aliyuncs.com/articles/ba11c04eda104aeb922ac145fc40a983.png) |\n| ![admin4.png](https://veport.oss-cn-beijing.aliyuncs.com/articles/95ac11550856e34974fdeaf245bb7f81.png) |\n| ![admin5.png](https://veport.oss-cn-beijing.aliyuncs.com/articles/07e6cafa2ebae034501d58e4a4bb6d3c.png) |\n| ![admin6.png](https://veport.oss-cn-beijing.aliyuncs.com/articles/b27720c9fb435206db88491ca0c1a117.png) |\n', 1, '', 2, 0, 1, 0, 34, '2025-05-21 16:41:44', '2026-05-03 06:54:59');
INSERT INTO `t_article` (`id`, `user_id`, `category_id`, `article_cover`, `article_title`, `article_content`, `article_type`, `original_url`, `is_top`, `is_delete`, `status`, `like_count`, `view_count`, `created_at`, `updated_at`) VALUES (5, 'root', 2, 'https://static.veweiyi.cn/blog/article/qinglong-20241115174624.jpg', '博客网站技术总结', '# 博客网站技术总结\n\n文章封面:  https://veport.oss-cn-beijing.aliyuncs.com/articles/cfeb11ab6be04ca78f24a0d8974a296d.png   \n文章类型: 1   \n文章分类: 网站搭建   \n文章标签: [vue 网站 springboot]   \n创建时间: 2022-01-21 12:21:31 +0800 CST\n\n文章内容:\n<div align=center>\n<img src=\"https://mms1.baidu.com/it/u=2815887849,1501151317&fm=253&app=138&f=JPEG\" width=150\" height=\"150\" />\n  <h1>ve-blog-golang</h1>\n\n<img src=\"https://img.shields.io/badge/golang-1.20-blue\"/>\n<img src=\"https://img.shields.io/badge/gin-1.9.0-lightBlue\"/>\n<img src=\"https://img.shields.io/badge/gorm-1.24.7-red\"/>\n<img src=\"https://img.shields.io/badge/redis-9.0.2-brightgreen\"/>\n<img src=\"https://img.shields.io/badge/swagger-v1.5.3-green\"/>\n\n</div>\n\n![](https://foruda.gitee.com/images/1708618984641188532/a7cca095_716974.png \"rainbow.png\")\n\n\n<div align=\"center\">\n  <a target=\"_blank\" href=\"https://blog.veweiyi.cn\">🖥️ 前台在线预览</a> |\n  <a target=\"_blank\" href=\"https://blog.veweiyi.cn/api/v1/swagger/index.html\">📑 前台接口文档</a> |\n</div>\n\n<div align=\"center\">\n  <a target=\"_blank\" href=\"https://admin.veweiyi.cn\">🖥️ 后台在线预览</a> |\n  <a target=\"_blank\" href=\"https://admin.veweiyi.cn/admin-api/v1/swagger/index.html\">📑 后台接口文档</a>\n</div>\n\n### 作者联系方式：\n\n* qq 791422171\n* 微信 wy791422171\n\n兴趣是第一驱动力。工作之余持续更新，持续学习新技术。\n\n## 📚 项目简介\n\nve-blog 是一个现代化的全栈博客系统，采用 Go 语言开发后端，基于微服务架构，提供完整的博客解决方案。\n\n## 项目预览\n\n### 1. 项目截图\n\n### 移动端前台\n\n|                                                                                                                    |                                                                                                                    |\n|--------------------------------------------------------------------------------------------------------------------|--------------------------------------------------------------------------------------------------------------------|\n| <img src=\"https://veport.oss-cn-beijing.aliyuncs.com/articles/3d6d442430f9de01c2e7cbcb914c1a2a.jpg\" width=\"300\" /> | <img src=\"https://veport.oss-cn-beijing.aliyuncs.com/articles/12431b4262b7e9c2fe1c10d2a9797ad1.jpg\" width=\"300\" /> |\n\n### PC端前台\n\n|                                                                                                                       |\n|-----------------------------------------------------------------------------------------------------------------------|\n| ![截屏20220219 22.54.49.png]( https://veport.oss-cn-beijing.aliyuncs.com/articles/f5e11e5a67fd322be0487d1b520ec9a4.png) |\n| ![截屏20220219 23.06.58.png]( https://veport.oss-cn-beijing.aliyuncs.com/articles/f36f002e31660912dcd76d34dcca538b.png) |\n| ![截屏20220219 23.10.43.png]( https://veport.oss-cn-beijing.aliyuncs.com/articles/eac9f4a203d6377efa37edb912166e60.png) |\n\n### PC端后台\n\n|                                                                                                          |\n|----------------------------------------------------------------------------------------------------------|\n| ![admin1.png]( https://veport.oss-cn-beijing.aliyuncs.com/articles/6ec21b7f32199a0c1418a9968d0b44f6.png) |\n| ![admin2.png]( https://veport.oss-cn-beijing.aliyuncs.com/articles/0e7fb892d411d34da39c3d4ab1142ed6.png) |\n\n## ✨ 核心特性\n\n### 1. 技术栈\n\n- **后端**：Golang + Go-zero + gRPC + Gorm + Redis + RabbitMQ + Kafka\n- **前端**：Vue3 + Pinia + TypeScript + Element Plus + Naive UI\n- **部署**：Docker Compose 一键部署\n\n### 2. 系统功能\n\n- **用户系统**：支持账号密码、Github、QQ、微信等多种登录方式\n- **权限管理**：基于 RBAC 的权限模型，支持动态权限、菜单和路由\n- **文章管理**：支持 Markdown 编辑器、文章分类、标签、评论、点赞\n- **社交功能**：说说、友链、相册、留言弹幕墙、音乐播放器、聊天室\n- **消息通知**：评论回复邮件提醒、系统消息推送\n\n### 3. 技术亮点\n\n- **微服务架构**：采用 go-zero 框架，支持服务注册发现、负载均衡，实现高可用架构\n- **高性能**：使用 Redis 缓存、消息队列优化，支持高并发访问，轻松应对流量高峰\n- **安全性**：JWT 认证、数据加密、权限控制，全方位保障系统安全\n- **可扩展性**：模块化设计，支持功能扩展和定制，满足个性化需求\n- **开发效率**：提供完整的代码生成工具，快速开发新功能\n\n## 📁 项目源码\n\n| 项目               | 功能     | Github                                                               |\n|------------------|--------|----------------------------------------------------------------------|\n| ve-blog-golang   | 博客后端服务 | [ve-blog-golang](https://github.com/ve-weiyi/ve-blog-golang.git)     |\n| ve-blog-naive    | 博客前台展示 | [ve-blog-naive](https://github.com/ve-weiyi/ve-blog-naive.git)       |\n| ve-admin-element | 博客后台管理 | [ve-admin-element](https://github.com/ve-weiyi/ve-admin-element.git) |\n\n## 🛠️ 环境要求\n\n- Go 1.20+\n- MySQL 8.0+\n- Redis 6.2+\n- Docker & Docker Compose\n\n## 🔧 开发工具\n\n- IDE: Intellij IDEA Ultimate\n- 数据库: Navicat\n- Redis: Another Redis Desktop Manager\n- 容器: Docker Desktop\n\n## 📈 后续计划\n\n- [ ] 用户评论邮件提醒\n- [ ] 集成 ElasticSearch 搜索引擎\n- [ ] 添加 Prometheus 监控\n- [ ] 集成 ChatGPT 聊天功能\n- [ ] 优化性能监控\n- [ ] 增加更多社交功能\n\n## 🙏 致谢\n\n感谢以下项目的启发：\n\n- [风丶宇的博客(已删库)](https://github.com/X1192176811/blog)\n- [阿冬的个人博客](https://github.com/ttkican/Blog)\n- [vue3-element-admin](https://github.com/youlaitech/vue3-element-admin)\n', 1, '', 2, 0, 1, 0, 89, '2025-05-21 16:42:43', '2026-05-14 12:27:41');
